import pandas as pd
import gc
from collections import defaultdict

def execute_rule0(original_df: pd.DataFrame):
    """
    This function verifies the rule: ['machine_id'] --> ['factory_zone']
    """

    df = original_df
    total_row_num_of_original_df = len(df)

    # --------------------------------------------------
    # 2) Limit df to only the relevant columns to reduce memory usage
    # --------------------------------------------------
    left_columns = ['machine_id']
    right_columns = ['factory_zone']

    relevant_cols = list(set(left_columns + right_columns))
    df_relevant = df[relevant_cols].copy(deep=False)

    # --------------------------------------------------
    # 3) Drop rows where any of the left_columns is None/NaN
    # --------------------------------------------------
    df_relevant.dropna(subset=left_columns, how='any', inplace=True)

    # Initialize dictionaries to collect results
    satisfactions_dict = {}
    violations_dict = {}

    # --------------------------------------------------
    # 4) Group the dataframe by the values in the left_columns
    # --------------------------------------------------
    grouped_df = df_relevant.groupby(left_columns)

    # ---------- EARLY EXIT 1: All groups are single-row ----------
    if all(len(group) == 1 for _, group in grouped_df):
        del df_relevant
        del grouped_df
        gc.collect()
        return {
            "support": -1,
            "confidence": -1,
            "satisfactions": None,
            "violations": None,
            "total_satisfactions": None,
            "total_violations": None,
        }

    # ---------- EARLY EXIT 2: All right column values are missing ----------
    if df_relevant[right_columns].isnull().all(axis=1).all():
        del df_relevant
        del grouped_df
        gc.collect()
        return {
            "support": -2,
            "confidence": -2,
            "satisfactions": None,
            "violations": None,
            "total_satisfactions": None,
            "total_violations": None,
        }

    for group_key, group_data in grouped_df:
        if len(left_columns) == 1:
            left_part_tuple = (left_columns[0], group_key)
        else:
            left_part_tuple = tuple((col, val) for col, val in zip(left_columns, group_key))

        if len(group_data) == 1:
            row_index = int(group_data.index[0])
            row = group_data.iloc[0]
            if len(right_columns) == 1:
                col = right_columns[0]
                val = row[col]
                if pd.isna(val):
                    val = None
                right_part_key = (col, val)
            else:
                right_part_key = tuple(
                    (col, None if pd.isna(row[col]) else row[col])
                    for col in right_columns
                )

            if left_part_tuple not in satisfactions_dict:
                satisfactions_dict[left_part_tuple] = {}
            satisfactions_dict[left_part_tuple].setdefault(right_part_key, [])
            satisfactions_dict[left_part_tuple][right_part_key].append(row_index)
            continue

        combos_dict = defaultdict(list)
        for row in group_data.itertuples(index=True):
            idx = int(row.Index)
            if len(right_columns) == 1:
                col = right_columns[0]
                val = getattr(row, col)
                if pd.isna(val):
                    val = None
                rc_tuple = (col, val)
            else:
                rc_tuple = tuple(
                    (col, None if pd.isna(getattr(row, col)) else getattr(row, col))
                    for col in right_columns
                )
            combos_dict[rc_tuple].append(idx)

        if len(combos_dict) == 1:
            (right_part_key, row_indices), = combos_dict.items()
            if left_part_tuple not in satisfactions_dict:
                satisfactions_dict[left_part_tuple] = {}
            satisfactions_dict[left_part_tuple][right_part_key] = row_indices
        else:
            if left_part_tuple not in violations_dict:
                violations_dict[left_part_tuple] = {}

            if left_part_tuple not in satisfactions_dict:
                satisfactions_dict[left_part_tuple] = []

            for right_part_key, row_indices in combos_dict.items():
                violations_dict[left_part_tuple][right_part_key] = row_indices
                # rows within each row indices satisfy the rule
                satisfactions_dict[left_part_tuple].append({right_part_key: row_indices})

    # --------------------------------------------------
    # 5) Output in standardized representation format
    # --------------------------------------------------
    satisfactions = satisfactions_dict
    violations = violations_dict

     # --------------------------------------------------
    # 6) Calculate support and confidence
    # --------------------------------------------------
    num_satisfaction_groups = len(satisfactions)
    num_violation_groups = len(violations)
    if num_satisfaction_groups + num_violation_groups > 0:
        confidence = num_satisfaction_groups / (num_satisfaction_groups + num_violation_groups)
    else:
        confidence = -1

    all_rows = set()
    for group in satisfactions.values():
        if isinstance(group, dict):
            for rows in group.values():
                if isinstance(rows, list):
                    all_rows.update(rows)
                else:
                    all_rows.add(rows)
        if isinstance(group, list):
            for sub_dict in group:
                for rows in sub_dict.values():
                    if isinstance(rows, list):
                        all_rows.update(rows)
                    else:
                        all_rows.add(rows)

    for group in violations.values():
        if isinstance(group, dict):
            for rows in group.values():
                if isinstance(rows, list):
                    all_rows.update(rows)
                else:
                    all_rows.add(rows)

        if isinstance(group, list):
            for sub_dict in group:
                for rows in sub_dict.values():
                    if isinstance(rows, list):
                        all_rows.update(rows)
                    else:
                        all_rows.add(rows)

    support = len(all_rows) / total_row_num_of_original_df

    # --------------------------------------------------
    # 7) Delete temporary data structures and force garbage collection
    # --------------------------------------------------
    del df_relevant
    del grouped_df
    gc.collect()

    return {
        "support": support,
        "confidence": confidence,
        "satisfactions": satisfactions,
        "violations": violations,
        "total_satisfactions": num_satisfaction_groups,
        "total_violations": num_violation_groups,
    }
